// Temas rotativos: se elige según la semana ISO + día (martes/jueves) para no repetir seguido.
const temas = [
  { label: 'Capacitación con realidad virtual en minería (Chile)', query: 'capacitacion realidad virtual mineria' },
  { label: 'Realidad virtual y XR en Chile', query: 'realidad virtual Chile empresas' },
  { label: 'Videos 3D y simulación para minería e industria', query: 'simulacion 3D animacion industria mineria' },
  { label: 'Realidad aumentada en la industria', query: 'realidad aumentada industria mantenimiento' },
  { label: 'Hardware XR: visores, chips y lentes inteligentes', query: 'visores realidad virtual chip XR' },
  { label: 'IA aplicada a XR y entrenamiento industrial', query: 'inteligencia artificial realidad virtual entrenamiento' },
  { label: 'Gemelos digitales en minería e industria', query: 'gemelo digital mineria industria' },
  { label: 'Seguridad minera y nuevas tecnologías', query: 'seguridad minera tecnologia capacitacion' },
];
const now = new Date();
const start = new Date(Date.UTC(now.getUTCFullYear(), 0, 1));
const week = Math.floor(((now - start) / 86400000 + start.getUTCDay() + 1) / 7);
const slot = now.getDay() === 4 ? 1 : 0; // jueves=1, cualquier otro día=0
const tema = temas[(week * 2 + slot) % temas.length];
const rssUrl = 'https://www.bing.com/news/search?q=' + encodeURIComponent(tema.query) + '&format=RSS&mkt=es-CL';
return [{ json: { topic: tema.label, tema: tema.label, query: tema.query, rssUrl } }];

// Parsea el RSS de Bing News y arma la petición para DeepSeek.
const xml = $json.data || '';
const decode = (s) => (s || '')
  .replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, '$1')
  .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"').replace(/&#39;|&apos;/g, "'").trim();

const todas = [];
const items = xml.match(/<item>[\s\S]*?<\/item>/g) || [];
for (const it of items) {
  const title = decode((it.match(/<title>([\s\S]*?)<\/title>/) || [])[1]);
  let link = decode((it.match(/<link>([\s\S]*?)<\/link>/) || [])[1]);
  const pub = decode((it.match(/<pubDate>([\s\S]*?)<\/pubDate>/) || [])[1]);
  // Bing envuelve la URL real en apiclick.aspx?...url=<encoded>
  const m = link.match(/[?&]url=([^&]+)/);
  if (m) link = decodeURIComponent(m[1]);
  if (!title || !link || /bing\.com/i.test(link)) continue;
  const d = new Date(pub);
  let fuente = '';
  try { fuente = new URL(link).hostname.replace(/^www\./, ''); } catch (e) {}
  if (!todas.some(n => n.link === link)) todas.push({ title, link, fuente, ts: isNaN(d) ? 0 : d.getTime(), fecha: isNaN(d) ? '' : d.toISOString().slice(0, 10) });
}
todas.sort((x, y) => y.ts - x.ts);
// Solo noticias de los últimos 7 días. Si no hay ninguna, el prompt indica escribir un artículo evergreen sin citas.
const noticias = todas.filter(n => n.ts && (Date.now() - n.ts) <= 7 * 86400000).slice(0, 8);

const fecha = new Date().toLocaleDateString('es-CL', { year: 'numeric', month: 'long', day: 'numeric' });
const listado = noticias.length
  ? noticias.map((n, i) => (i + 1) + '. ' + n.title + ' | ' + n.fuente + ' | ' + n.link + (n.fecha ? ' | ' + n.fecha : '')).join('\n')
  : '(No hay fuentes verificables disponibles hoy: no inventes URLs. La ejecución debe detenerse si no puede incluir al menos una fuente HTTPS real.)';

const system = [
'Eres el redactor senior de contenidos SEO del blog de Doble 3D Studio (doble3d.cl), estudio chileno especializado en: capacitación con realidad virtual para minería e industrias de alto riesgo, videos y animación 3D técnica, realidad aumentada, aplicaciones WebGL, y CORE (plataforma propia de gestión y métricas de entrenamiento inmersivo, integrable a los LMS del cliente). Clientes destacados: Codelco, Minera Centinela, FlyWithUs y FLS (FLSmidth). Diferenciales: desarrollo a medida en Chile, integración con las plataformas que el cliente ya usa (LMS/SCORM) y soporte postventa perpetuo.',
'',
'Escribes en español chileno neutro y profesional. Cuando hablas de Doble 3D usas primera persona plural ("En Doble 3D creemos...").',
'',
'ENLACES INTERNOS disponibles (integra 2 o 3 de forma natural y contextual dentro del cuerpo, con anchor text descriptivo):',
'- https://doble3d.cl/servicios/realidad-virtual/ (capacitación VR industrial/minería)',
'- https://doble3d.cl/servicios/animacion-3d/ (videos y animación 3D técnica)',
'- https://doble3d.cl/servicios/core/ (plataforma CORE)',
'- https://doble3d.cl/servicios/gamificacion-scorm/ (apps gamificadas SCORM)',
'- https://doble3d.cl/app-webgl/ (aplicaciones WebGL)',
'',
'ESTRUCTURA OBLIGATORIA de content (NO incluyas H1, el título va aparte; NO incluyas los bloques de cierre, se agregan automáticamente):',
'1) Un párrafo inicial de 60 a 90 palabras que resuma la noticia con datos concretos y contenga la focus keyword de forma natural (respuesta directa, optimizada para motores de respuesta/AEO).',
'2) De 3 a 5 secciones <h2> (al menos dos formuladas como pregunta), con párrafos <p> de 2 a 4 oraciones. Cita cada medio con <a href="URL" target="_blank" rel="noopener">nombre del medio</a>. USA SOLO las URLs de la lista de noticias entregada; está PROHIBIDO inventar URLs externas.',
'3) Una sección que conecte la noticia con el trabajo de Doble 3D en minería/industria chilena (aporte de valor, sin venta dura).',
'4) Al final: <h2>Preguntas frecuentes</h2> con exactamente 4 bloques de <h3>(pregunta)</h3> seguido de <p>(respuesta de 40 a 60 palabras, autocontenida, con entidades y cifras)</p>. Las mismas 4 preguntas/respuestas van en el array faq.',
'',
'REGLAS SEO (Yoast): focus_keyword long-tail en minúsculas y sin tildes (ej: "capacitacion realidad virtual mineria"); la keyword aparece en el primer párrafo, en al menos un H2 y en el slug; meta_title de máximo 60 caracteres comenzando con la keyword o muy cerca del inicio; meta_description de 120 a 155 caracteres con la keyword y un llamado a la acción; slug corto de 3 a 6 palabras; excerpt de 1 a 2 oraciones. Artículo de 800 a 1200 palabras.',
'',
'REGLAS AEO/LLMs: respuestas directas y autocontenidas, cifras y datos concretos, nombres completos de empresas y tecnologías, lenguaje declarativo y verificable.',
'',
'RESPONDE ÚNICAMENTE un objeto JSON válido con estas claves exactas:',
'{',
'  "titulo": "máx 65 caracteres, atractivo, incluye la keyword o parte de ella",',
'  "titulo_imagen": "título visual breve, máx 65 caracteres",',
'  "subtitulo_imagen": "máx 60 caracteres, complementa al título sin repetirlo",',
'  "tag_top": "etiqueta de categoría para la imagen, máx 30 caracteres, MAYÚSCULAS, ej: CAPACITACIÓN INMERSIVA INDUSTRIAL",',
'  "tag_1": "primera entidad clave de la noticia, máx 16 caracteres, ej: CODELCO o QUALCOMM",',
'  "tag_2": "segunda entidad o tecnología clave, máx 16 caracteres, ej: AULA 4.0 o 48 TOPS",',
'  "slug": "en-minusculas-con-guiones",',
'  "meta_title": "máx 60 caracteres",',
'  "meta_description": "120 a 155 caracteres",',
'  "focus_keyword": "keyword long-tail",',
'  "excerpt": "1-2 oraciones",',
'  "categoria": "UNA de: Realidad Virtual en minería | Realidad Virtual | Videos 3D Minería | Realidad Mixta | Inteligencia Artificial | Innovación | Tecnología | WebGL en minería",',
'  "tags": ["3 a 5 tags en español"],',
'  "fuentes": [{"titulo":"Nombre de la fuente","url":"https://example.org/documento","fecha":"2026-07-01","medio":"Organización responsable"}],',
'  "content": "el cuerpo HTML según la estructura",',
'  "faq": [{"q": "pregunta", "a": "respuesta en texto plano"}] // exactamente 4',
'}'
].join('\n');

