return [{ json: {
  noticiasEncontradas: noticias.length,
  body: {
    model: 'deepseek-v4-pro',
    messages: [ { role: 'system', content: system }, { role: 'user', content: user } ],
    response_format: { type: 'json_object' },
    temperature: 0.7,
    max_tokens: 12000,
    thinking: { type: 'disabled' },
  },
} }];

// Ensambla únicamente un artículo que ya superó ambas validaciones.
const STATUS = 'draft';
const WP = 'https://doble3d.cl/wp-json/wp/v2';
const AUTH = { Authorization: 'Basic WORDPRESS_APP_PASSWORD_REDACTED' };
const a = $json.article;
if (!a) throw new Error('MISSING_VALIDATED_ARTICLE');

const CATS = { 'realidad virtual en minería': 14, 'realidad virtual en mineria': 14, 'realidad virtual': 39, 'videos 3d minería': 1, 'videos 3d mineria': 1, 'realidad mixta': 15, 'inteligencia artificial': 32, 'innovación': 61, 'innovacion': 61, 'tecnología': 52, 'tecnologia': 52, 'webgl en minería': 17, 'webgl en mineria': 17 };
const catId = CATS[(a.categoria || '').toLowerCase().trim()] || 39;

// Resolver tags: buscar cada uno en WP, crear los que no existan.
const tagIds = [];
for (const nombre of (a.tags || []).slice(0, 5)) {
  const name = String(nombre).trim();
  if (!name) continue;
  try {
    const found = await this.helpers.httpRequest({ method: 'GET', url: WP + '/tags', qs: { search: name, per_page: 10 }, headers: AUTH, json: true });
    const exact = (found || []).find(t => t.name.toLowerCase() === name.toLowerCase());
    if (exact) { tagIds.push(exact.id); continue; }
    const created = await this.helpers.httpRequest({ method: 'POST', url: WP + '/tags', body: { name }, headers: AUTH, json: true });
    if (created && created.id) tagIds.push(created.id);
  } catch (e) { /* un tag fallido no detiene la publicación */ }
}

// Schema JSON-LD FAQPage (AEO) a partir del array faq.
const clean = (s) => String(s || '').replace(/<[^>]*>/g, '').trim();
const faqLd = {
  '@context': 'https://schema.org',
  '@type': 'FAQPage',
  mainEntity: a.faq.slice(0, 6).map(f => ({
    '@type': 'Question', name: clean(f.q),
    acceptedAnswer: { '@type': 'Answer', text: clean(f.a) },
  })),
};

// Bloques fijos de cierre (enlaces internos + CTA), como en los templates.
const bloqueCierre = [
'<h2>Para profundizar en capacitación VR para minería</h2>',
'<ul>',
'<li><a href="https://doble3d.cl/servicios/realidad-virtual/">Realidad virtual industrial para entrenamiento en minería</a></li>',
'<li><a href="https://doble3d.cl/servicios/animacion-3d/">Animación 3D técnica para procesos industriales</a></li>',
'<li><a href="https://doble3d.cl/servicios/gamificacion-scorm/">Apps gamificadas con SCORM para entrenamiento industrial</a></li>',
'</ul>',
'<p>En Doble 3D desarrollamos <a href="https://doble3d.cl/servicios/realidad-virtual/">capacitación en realidad virtual</a> para faenas mineras tier-1 como Codelco, Minera Centinela y FlyWithUs, y <a href="https://doble3d.cl/servicios/animacion-3d/">videos 3D para minería</a> para clientes como FLS (FLSmidth). Centraliza y mide tu entrenamiento inmersivo con <a href="https://doble3d.cl/servicios/core/">CORE</a>.</p>',
'<h2>¿Quieres llevar la capacitación inmersiva industrial a tu operación?</h2>',
'<p>En Doble 3D Studio diseñamos experiencias inmersivas a medida para minería e industrias de alto riesgo, integradas a las plataformas que ya usas, con soporte postventa perpetuo.</p>',
'<p>👉 <a href="https://wa.me/56958015971" target="_blank" rel="noopener">Conversemos por WhatsApp</a><br>🌐 <a href="https://doble3d.cl/servicios/">Conoce más</a></p>',
'<script type="application/ld+json">' + JSON.stringify(faqLd) + '</script>',
].join('\n');

const subt = String(a.subtitulo_imagen || a.focus_keyword).slice(0, 60);
const tagTop = String(a.tag_top).slice(0, 32);
const tag1 = String(a.tag_1).slice(0, 18);
const tag2 = String(a.tag_2).slice(0, 18);

return [{ json: {
  status: STATUS,
  titulo: a.titulo.trim(),
  slug: a.slug,
  metaTitle: a.meta_title.trim(),
  metaDesc: a.meta_description.trim(),
  focusKeyword: a.focus_keyword.trim(),
  excerpt: a.excerpt.trim(),
  categoria: catId,
