  content: a.content.trim() + '\n' + bloqueCierre,
  sources: a.fuentes,
  imageUrl: 'https://doble3d.cl/image-gen.php?titulo=' + encodeURIComponent(a.titulo_imagen) + '&subtitulo=' + encodeURIComponent(subt) + '&tag_top=' + encodeURIComponent(tagTop) + '&tag_1=' + encodeURIComponent(tag1) + '&tag_2=' + encodeURIComponent(tag2),
  filename: a.slug + '.webp',
} }];

